#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Read the message type (uint16_t)
    uint16_t message_type = stream.get<uint16_t>();

    // Read the body length (uint32_t)
    uint32_t body_length = stream.get<uint32_t>();

    // Skip the body data based on the body length
    stream.skip(body_length);

    // Read the footer (uint32_t)
    uint32_t footer = stream.get<uint32_t>();

    // Return the MessageHeader structure
    return MessageHeader{message_type, body_length, footer};
}
```

