struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Preview first byte (data_type) without advancing read pointer
    if (stream.remaining() < 1) {
        return result; // Not enough data for data_type
    }

    // Peek at the data_type without consuming it
    result.data_type = stream.peek<uint8_t>();

    // Check if we have enough data for header (data_type + item_count)
    if (stream.remaining() < 5) { // 1 byte for data_type + 4 bytes for item_count
        return result;
    }

    // Read the actual data_type (consumes the byte)
    stream >> result.data_type;

    // Read item_count
    uint32_t item_count;
    stream >> item_count;

    // Check if we have enough data for all items
    size_t item_size = (result.data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    if (stream.remaining() < item_count * item_size) {
        return result; // Not enough data for all items
    }

    // Read items based on data_type
    if (result.data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (result.data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
