```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Check available data - header size is 8 bytes (4 + 2 + 2)
    if (stream.available() < sizeof(PacketHeader)) {
        // Handle error - not enough data for header
        // You might want to throw an exception or return a default header
        return PacketHeader{0, 0, 0};
    }

    // Get the read pointer using buffer_adaptor's data access
    const uint8_t* read_ptr = adaptor.data() + stream.tellg();

    // Get a zero-copy view of the header using binary_stream's view method
    auto header_view = stream.view(sizeof(PacketHeader));

    // Extract header fields from the zero-copy view
    PacketHeader header;

    // Since we have a span of bytes, we need to extract the fields properly
    // We can use memcpy or reinterpret the data (being careful with alignment)
    if (header_view.size() >= sizeof(PacketHeader)) {
        // Safe approach: copy the data to avoid alignment issues
        std::memcpy(&header, header_view.data(), sizeof(PacketHeader));

        // Alternative: if you want to be more explicit about the structure:
        // header.magic = *reinterpret_cast<const uint32_t*>(header_view.data());
        // header.version = *reinterpret_cast<const uint16_t*>(header_view.data() + 4);
        // header.flags = *reinterpret_cast<const uint16_t*>(header_view.data() + 6);
    }

    // Advance the stream position by the header size
    stream.skip(sizeof(PacketHeader));

    return header;
}
```

