// Include the implementation
#include "implementation.hpp"

// Helper function to create test buffer
std::vector<uint8_t> create_message_buffer(uint32_t header, const std::string& message) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << header;
    stream << hexi::null_terminated(message);
    return buffer;
}

TEST(BufferReadView, ReadHeaderAndMessage) {
    auto buffer = create_message_buffer(12345, "Hello World");

    MessagePacket packet = read_header_and_message(buffer);

    EXPECT_EQ(12345, packet.header);
    EXPECT_EQ("Hello World", packet.message);
}

TEST(BufferReadView, ReadEmptyMessage) {
    auto buffer = create_message_buffer(999, "");

    MessagePacket packet = read_header_and_message(buffer);

    EXPECT_EQ(999, packet.header);
    EXPECT_TRUE(packet.message.empty());
}

