```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Read the header (uint32_t)
    uint32_t header;
    stream >> header;

    // Read the null-terminated message using view method
    // Find the position of the null terminator
    auto null_pos = adaptor.find_first_of(0);

    // Get the string view up to the null terminator
    std::string_view message = adaptor.view(null_pos);

    // Advance the read pointer past the null terminator
    adaptor.advance_read(null_pos + 1);

    return MessagePacket{header, message};
}
```

