    // Get the thread-local allocator instance
    auto* thread_allocator = allocator.allocator();

    // Clean up any remaining allocations and thread-specific resources
    // This ensures no memory leaks when the thread exits

    // If the allocator provides an explicit cleanup method, call it
    if constexpr (requires { thread_allocator->cleanup_thread(); }) {
