        std::cout << "Re-allocated block " << i + 1 << " at address: " << ptr 
                  << " (value: " << *ptr << ")\n";
    }

    // Verify LIFO behavior
    std::cout << "\nVerification of LIFO behavior:\n";
    bool lifo_correct = true;
    for (size_t i = 0; i < element_count; ++i) {
        if (reallocated_ptrs[i] != allocated_ptrs[element_count - 1 - i]) {
            lifo_correct = false;
            break;
        }
    }

    if (lifo_correct) {
        std::cout << "✓ LIFO behavior confirmed: Blocks were re-allocated in reverse order\n";
        std::cout << "  This demonstrates that push() adds to head and pop() removes from head\n";
    } else {
        std::cout << "✗ LIFO behavior not as expected\n";
    }

    // Clean up
    for (auto ptr : reallocated_ptrs) {
        allocator.deallocate(ptr);
    }

    std::cout << "\nFree list management summary:\n";
    std::cout << "- push(): Adds freed block to head of free list\n";
    std::cout << "- pop(): Removes and returns head block from free list\n";
    std::cout << "- Result: Last freed block is first to be re-allocated (LIFO)\n";
}

