#include <gtest/gtest.h>
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <cstring>

// Include the implementation
#include "implementation.hpp"

TEST(IntrusiveStorage, PreviewDataWithoutConsuming) {
    hexi::detail::intrusive_storage<1024> storage;
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5, 6, 7, 8};
    storage.write(test_data.data(), test_data.size());

    // Preview data - should not advance read pointer
    auto preview1 = preview_data_without_consuming(storage, 3);
    auto preview2 = preview_data_without_consuming(storage, 3);

    EXPECT_EQ(3, preview1.size());
    EXPECT_EQ(1, preview1[0]);
    EXPECT_EQ(2, preview1[1]);
    EXPECT_EQ(3, preview1[2]);

    // Both previews should be the same (read pointer not advanced)
    EXPECT_EQ(preview1, preview2);

    // Buffer size should remain unchanged
    EXPECT_EQ(test_data.size(), storage.size());
}

TEST(IntrusiveStorage, CheckBufferStatus) {
    hexi::detail::intrusive_storage<1024> storage;
    std::vector<uint8_t> test_data = {10, 20, 30, 40};
    storage.write(test_data.data(), test_data.size());

    auto status = check_buffer_status(storage);

    EXPECT_EQ(test_data.size(), status.readable_size);
    EXPECT_GE(status.free_space, 0);
    EXPECT_EQ(1024 - test_data.size(), status.free_space);
}

TEST(IntrusiveStorage, ResetBuffer) {
    hexi::detail::intrusive_storage<1024> storage;
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5};
    storage.write(test_data.data(), test_data.size());

    EXPECT_EQ(test_data.size(), storage.size());

    reset_buffer(storage);

    EXPECT_EQ(0, storage.size());
    EXPECT_EQ(1024, storage.free());
}

