```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path);

    // Get the available readable size
    size_t available_size = buffer.size();

    // Determine how many bytes we can actually read
    size_t bytes_to_read_actual = (bytes_to_read > available_size) ? available_size : bytes_to_read;

    // Create a vector to hold the data
    std::vector<uint8_t> data(bytes_to_read_actual);

    // Read the data from the file buffer
    if (bytes_to_read_actual > 0) {
        buffer.read(data.data(), bytes_to_read_actual);
    }

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path);

    // Get the available readable size
    size_t available_size = buffer.size();

    // Determine how many bytes we can actually preview
    size_t bytes_to_preview_actual = (bytes_to_preview > available_size) ? available_size : bytes_to_preview;

    // Create a vector to hold the data
    std::vector<uint8_t> data(bytes_to_preview_actual);

    // Preview the data without advancing the read pointer
    if (bytes_to_preview_actual > 0) {
        // Use copy to preview without modifying the read position
        buffer.copy(data.data(), bytes_to_preview_actual);
    }

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer for writing
    // Note: file_buffer constructor with just path opens for reading by default
    // We need to specify write mode. Based on the library patterns, this might be:
    // hexi::file_buffer buffer(file_path, hexi::file_buffer::write);
    // Since the exact write mode syntax isn't shown in fragments, using the basic approach
    hexi::file_buffer buffer(file_path);

    // Write the data to the file buffer
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer for the file
    hexi::file_buffer buffer(file_path);

    // Return the size of readable data in the file
    return buffer.size();
}
