#include <gtest/gtest.h>
#include <hexi/file_buffer.h>
#include <cstdint>
#include <filesystem>
#include <fstream>

// Include the implementation
#include "implementation.hpp"

// Helper function to write data to file
void write_to_file(const std::filesystem::path& file_path, const void* data, size_t size) {
    std::ofstream file(file_path, std::ios::binary);
    file.write(reinterpret_cast<const char*>(data), size);
    file.close();
}

TEST(FileBuffer, ReadInt32) {
    std::filesystem::path test_file = "test_int32.bin";
    int32_t original_value = -123456;
    write_to_file(test_file, &original_value, sizeof(int32_t));

    int32_t read_value = read_int32_from_file(test_file);

    EXPECT_EQ(original_value, read_value);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, ReadFloat) {
    std::filesystem::path test_file = "test_float.bin";
    float original_value = 3.14159f;
    write_to_file(test_file, &original_value, sizeof(float));

    float read_value = read_float_from_file(test_file);

    EXPECT_FLOAT_EQ(original_value, read_value);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, ReadInt32Zero) {
    std::filesystem::path test_file = "test_int32_zero.bin";
    int32_t original_value = 0;
    write_to_file(test_file, &original_value, sizeof(int32_t));

    int32_t read_value = read_int32_from_file(test_file);

    EXPECT_EQ(0, read_value);

    std::filesystem::remove(test_file);
}

