    UserData data1, data2;
    data1.user_id = 100;
    data1.name = "user1";
    data2.user_id = 200;
    data2.name = "user2";

    serialize_object(writer, data1);
    serialize_object(writer, data2);

    UserData result1, result2;
    deserialize_object(reader, result1);
    deserialize_object(reader, result2);

    EXPECT_EQ(data1.user_id, result1.user_id);
    EXPECT_EQ(data1.name, result1.name);
    EXPECT_EQ(data2.user_id, result2.user_id);
    EXPECT_EQ(data2.name, result2.name);
}

