#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the count of elements as uint32_t
    writer.write(static_cast<uint32_t>(container.size()));

    // Write each element in the container
    for (const auto& element : container) {
        writer.write(element);
    }
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the count of elements
    uint32_t count = reader.read<uint32_t>();

    // Create a vector with the appropriate size
    std::vector<uint32_t> container;
    container.reserve(count);

    // Read each element and add to the vector
    for (uint32_t i = 0; i < count; ++i) {
        container.push_back(reader.read<uint32_t>());
    }

    return container;
}
```

The implementation follows the standard pattern for reading/writing containers with a prefixed count:

1. **write_container_to_stream**:
   - First writes the size of the vector as a `uint32_t`
   - Then iterates through each element and writes it as `uint32_t`

2. **read_container_from_stream**:
   - First reads the count as `uint32_t`
   - Reserves space in the vector for efficiency
   - Reads each element and adds it to the vector

This approach ensures that the container can be properly serialized and deserialized while maintaining the correct element order and count.

