#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, SkipBytes) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value1 = 100, value2 = 200;
    adaptor.write(&value1, sizeof(value1));
    adaptor.write(&value2, sizeof(value2));

    skip_bytes_in_buffer(adaptor, sizeof(value1));

    uint32_t read_value = 0;
    adaptor.read(&read_value, sizeof(read_value));

    EXPECT_EQ(value2, read_value);
}

TEST(BufferAdaptor, ReadHeaderAndSkipBody) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    MessageHeader header;
    header.message_type = 123;
    header.body_length = 8;

    uint8_t body[8] = {1, 2, 3, 4, 5, 6, 7, 8};

    adaptor.write(&header.message_type, sizeof(header.message_type));
    adaptor.write(&header.body_length, sizeof(header.body_length));
    adaptor.write(body, sizeof(body));

    uint32_t footer = 999;
    adaptor.write(&footer, sizeof(footer));

    MessageHeader result = read_header_and_skip_body(adaptor);

    EXPECT_EQ(header.message_type, result.message_type);
    EXPECT_EQ(header.body_length, result.body_length);

    // Should be able to read footer now
    uint32_t read_footer = 0;
    adaptor.read(&read_footer, sizeof(read_footer));
    EXPECT_EQ(footer, read_footer);
}

TEST(BufferAdaptor, SkipEmptyBody) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    MessageHeader header;
    header.message_type = 456;
    header.body_length = 0;

    adaptor.write(&header.message_type, sizeof(header.message_type));
    adaptor.write(&header.body_length, sizeof(header.body_length));

    MessageHeader result = read_header_and_skip_body(adaptor);

    EXPECT_EQ(header.message_type, result.message_type);
    EXPECT_EQ(0, result.body_length);
}

