#include <gtest/gtest.h>
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

// Include the implementation
#include "implementation.hpp"

TEST(RegionOverlap, NoOverlap) {
    char buffer1[100] = {0};
    char buffer2[100] = {0};

    bool overlaps = check_regions_overlap(buffer1, sizeof(buffer1), buffer2, sizeof(buffer2));

    EXPECT_FALSE(overlaps);
}

TEST(RegionOverlap, OverlappingRegions) {
    char buffer[100] = {0};

    // Check if buffer overlaps with itself
    bool overlaps = check_regions_overlap(buffer, sizeof(buffer), buffer, sizeof(buffer));

    EXPECT_TRUE(overlaps);
}

TEST(RegionOverlap, PartialOverlap) {
    char buffer[100] = {0};

    // Check partial overlap
    bool overlaps = check_regions_overlap(buffer, 50, buffer + 30, 50);

    EXPECT_TRUE(overlaps);
}

TEST(RegionOverlap, AdjacentNoOverlap) {
    char buffer[100] = {0};

    // Adjacent regions should not overlap
    bool overlaps = check_regions_overlap(buffer, 50, buffer + 50, 50);

    EXPECT_FALSE(overlaps);
}

TEST(RegionOverlap, SafeMemoryCopy) {
    char source[10] = "123456789";
    char destination[10] = {0};

    bool success = safe_memory_copy(destination, source, sizeof(source));

    EXPECT_TRUE(success);
    EXPECT_EQ(0, std::memcmp(source, destination, sizeof(source)));
}

TEST(RegionOverlap, SafeMemoryCopyOverlap) {
    char buffer[10] = "123456789";

    // Try to copy overlapping regions - should fail
    bool success = safe_memory_copy(buffer + 2, buffer, 5);

    EXPECT_FALSE(success);
}

