std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() < input_data.size()) {
        // If not enough space, we can handle accordingly
        // For this example, we'll just proceed and let the adaptor handle it
    }

    // Write the data to the buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Create a read adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Check the readable size
    std::size_t readable_size = read_adaptor.size();
    std::vector<uint8_t> output_data(readable_size);

    // Read the data back
    read_adaptor.read(output_data.data(), readable_size);

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create a read adaptor for the buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data);

    // Get a pointer to the current read position
    const uint8_t* read_ptr = static_cast<const uint8_t*>(read_adaptor.read_ptr());

    // Use copy() to peek at data without moving the read cursor
    std::vector<uint8_t> peeked_data(peek_size);
    std::size_t actual_peek_size = read_adaptor.copy(peeked_data.data(), peek_size);

    // Resize the output to the actual amount peeked
