#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(TemplateReadWrite, WriteAndReadTypedData) {
    TypedData original;
    original.id = 12345;
    original.value = -100;
    original.ratio = 3.14159;

    auto buffer = write_typed_data(original);
    auto read_back = read_typed_data(buffer);

    EXPECT_EQ(original.id, read_back.id);
    EXPECT_EQ(original.value, read_back.value);
    EXPECT_DOUBLE_EQ(original.ratio, read_back.ratio);
}

TEST(TemplateReadWrite, DifferentTypes) {
    TypedData data;
    data.id = 0xFFFFFFFF;
    data.value = -32768;
    data.ratio = -123.456;

    auto buffer = write_typed_data(data);
    auto result = read_typed_data(buffer);

    EXPECT_EQ(0xFFFFFFFF, result.id);
    EXPECT_EQ(-32768, result.value);
    EXPECT_DOUBLE_EQ(-123.456, result.ratio);
}

TEST(TemplateReadWrite, TemplateCopy) {
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    uint32_t val = 0x12345678;
    adaptor.write(val);

    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    // Use template copy() to peek without advancing
    uint32_t peeked = 0;
    read_adaptor.copy(&peeked);

    EXPECT_EQ(0x12345678, peeked);

    // Verify read pointer hasn't advanced
    EXPECT_EQ(sizeof(uint32_t), read_adaptor.size());

    // Now read to consume
    uint32_t read_val = 0;
    read_adaptor.read(&read_val);

    EXPECT_EQ(0x12345678, read_val);
    EXPECT_EQ(0, read_adaptor.size());
}

