        std::size_t remaining = adaptor.size();
        std::size_t bytes_to_read = std::min(chunk_size, remaining);

        std::vector<uint8_t> chunk(bytes_to_read);
        adaptor.read(chunk.data(), bytes_to_read);

        // Append read data to result
        result.insert(result.end(), chunk.begin(), chunk.end());
    }

    return result;
}

