#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly (no endianness conversion needed for serialization)
        adaptor(sensor_id);

        // Convert and write each temperature value
        for (const auto& temp : temperatures) {
            float little_endian_temp = temp;
            hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(little_endian_temp);
            adaptor.write(little_endian_temp);
        }

        // Convert and write pressure value
        double little_endian_pressure = pressure;
        hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(little_endian_pressure);
        adaptor.write(little_endian_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor(sensor_id);

        // Read temperatures (size needs to be known or we need to handle dynamically)
        // For simplicity, assuming we know the size or it's handled elsewhere
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

